import{c as t,S as h,j as i,m as a}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Thi Đánh giá năng lực (HSA) - ĐHQG Hà Nội","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/thi-dgnl-hsa.md","filePath":"hoc-vien/thi-dgnl-hsa.md","lastUpdated":0}'),l={name:"hoc-vien/thi-dgnl-hsa.md"};function r(c,n,e,o,g,s){return h(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="thi-đanh-gia-nang-luc-hsa-đhqg-ha-noi" tabindex="-1">Thi Đánh giá năng lực (HSA) - ĐHQG Hà Nội <a class="header-anchor" href="#thi-đanh-gia-nang-luc-hsa-đhqg-ha-noi" aria-label="Permalink to “Thi Đánh giá năng lực (HSA) - ĐHQG Hà Nội”">​</a></h1><p><strong>Đường dẫn (làm bài):</strong> <code>https://lamsonedutech.vn/luyen-tap/danh-gia-nang-luc/:idCourse</code></p><h2 id="ve-ky-thi-hsa" tabindex="-1">Về kỳ thi HSA <a class="header-anchor" href="#ve-ky-thi-hsa" aria-label="Permalink to “Về kỳ thi HSA”">​</a></h2><p><strong>Đánh giá năng lực (ĐGNL)</strong> là kỳ thi do <strong>Đại học Quốc gia Hà Nội (VNU)</strong> tổ chức, được nhiều trường đại học sử dụng làm phương thức xét tuyển. Trên LamSơn Edutech, bạn có thể luyện đề mô phỏng đúng cấu trúc và quy chế của kỳ thi thật.</p><h2 id="cau-truc-đe-thi-hsa" tabindex="-1">Cấu trúc đề thi HSA <a class="header-anchor" href="#cau-truc-đe-thi-hsa" aria-label="Permalink to “Cấu trúc đề thi HSA”">​</a></h2><p>Đề thi gồm <strong>3 phần</strong>, tổng <strong>150 câu</strong>, <strong>195 phút</strong>:</p><table tabindex="0"><thead><tr><th style="text-align:center;">Phần</th><th>Tên phần</th><th style="text-align:center;">Số câu</th><th style="text-align:center;">Thời gian</th><th>Nội dung</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>1</strong></td><td>Tư duy định lượng</td><td style="text-align:center;">50</td><td style="text-align:center;">75 phút</td><td>Toán học, suy luận số liệu</td></tr><tr><td style="text-align:center;"><strong>2</strong></td><td>Tư duy định tính</td><td style="text-align:center;">50</td><td style="text-align:center;">60 phút</td><td>Ngữ văn, đọc hiểu, tiếng Việt</td></tr><tr><td style="text-align:center;"><strong>3</strong></td><td>Khoa học</td><td style="text-align:center;">50</td><td style="text-align:center;">60 phút</td><td>Lý, Hóa, Sinh, Sử, Địa (theo tổ hợp tự chọn)</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Quy chế quan trọng</p><ul><li><strong>Mỗi phần có đồng hồ riêng</strong>. Hết giờ phần này → tự chuyển sang phần kế.</li><li><strong>Không được quay lại phần trước</strong> sau khi đã chuyển.</li><li><strong>Trong cùng 1 phần</strong>, bạn có thể nhảy giữa các câu.</li><li>Dạng câu: trắc nghiệm 4 đáp án + <strong>điền số / đáp án ngắn</strong>.</li></ul></div><h2 id="tim-đe-hsa-o-đau" tabindex="-1">Tìm đề HSA ở đâu? <a class="header-anchor" href="#tim-đe-hsa-o-đau" aria-label="Permalink to “Tìm đề HSA ở đâu?”">​</a></h2><h3 id="tren-trang-chu" tabindex="-1">Trên trang chủ <a class="header-anchor" href="#tren-trang-chu" aria-label="Permalink to “Trên trang chủ”">​</a></h3><ul><li>Mục <strong>&quot;Luyện thi ĐGNL (HSA)&quot;</strong> - các đề mới nhất.</li></ul><h3 id="trong-khoa-hoc-cua-ban" tabindex="-1">Trong khóa học của bạn <a class="header-anchor" href="#trong-khoa-hoc-cua-ban" aria-label="Permalink to “Trong khóa học của bạn”">​</a></h3><ul><li>Khóa &quot;Luyện thi ĐGNL HSA&quot; có <strong>danh sách đề mẫu</strong> ở chương cuối / mục Đề thi thực chiến.</li></ul><h3 id="bo-đe-thi-hsa" tabindex="-1">Bộ đề thi HSA <a class="header-anchor" href="#bo-đe-thi-hsa" aria-label="Permalink to “Bộ đề thi HSA”">​</a></h3><ul><li>Vào menu <strong>Bộ đề thi</strong> → chọn bộ HSA năm 2026.</li></ul><h2 id="truoc-khi-vao-thi" tabindex="-1">Trước khi vào thi <a class="header-anchor" href="#truoc-khi-vao-thi" aria-label="Permalink to “Trước khi vào thi”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Chuẩn bị</p><ul><li>Chuẩn bị <strong>Internet ổn định</strong> - tốt nhất là kết nối có dây / Wi-Fi 5GHz.</li><li>Đóng các app khác trên máy.</li><li><strong>Máy tính / laptop</strong> màn hình ≥ 13 inch (đừng dùng điện thoại).</li><li>Giấy nháp + bút (cho phần Toán).</li><li>Pin laptop ≥ 50% hoặc cắm sạc.</li><li>Ngồi nơi yên tĩnh, <strong>không ai làm phiền</strong> trong 195 phút.</li><li>Đi vệ sinh trước khi vào.</li></ul></div><h2 id="trang-xem-truoc" tabindex="-1">Trang xem trước <a class="header-anchor" href="#trang-xem-truoc" aria-label="Permalink to “Trang xem trước”">​</a></h2><p>Khi bấm vào 1 đề HSA, trang <code>https://lamsonedutech.vn/luyen-tap/danh-gia-nang-luc/:idCourse</code> hiển thị:</p><ul><li>Tên đề</li><li>Cấu trúc (3 phần)</li><li>Tổng câu, tổng thời gian</li><li>Số lần đã làm, lần cao nhất bao nhiêu điểm</li><li>(Tùy chọn) <strong>Chọn tổ hợp Khoa học</strong>: KHTN (Lý-Hóa-Sinh) hoặc KHXH (Sử-Địa-GDCD)</li></ul><p>Bấm <strong>Bắt đầu thi</strong> để vào.</p><h2 id="giao-dien-thi-hsa" tabindex="-1">Giao diện thi HSA <a class="header-anchor" href="#giao-dien-thi-hsa" aria-label="Permalink to “Giao diện thi HSA”">​</a></h2><h3 id="phan-1-tu-duy-đinh-luong" tabindex="-1">Phần 1 - Tư duy định lượng <a class="header-anchor" href="#phan-1-tu-duy-đinh-luong" aria-label="Permalink to “Phần 1 - Tư duy định lượng”">​</a></h3><ul><li>Đồng hồ đếm ngược 75:00.</li><li>Nội dung: bài toán số liệu, đại số, hình học, xác suất, thống kê, suy luận.</li><li>Dạng câu: phần lớn trắc nghiệm 4 đáp án. Một số câu <strong>điền số</strong> (kết quả là một số nguyên, thập phân, hoặc phân số).</li></ul><h3 id="phan-2-tu-duy-đinh-tinh" tabindex="-1">Phần 2 - Tư duy định tính <a class="header-anchor" href="#phan-2-tu-duy-đinh-tinh" aria-label="Permalink to “Phần 2 - Tư duy định tính”">​</a></h3><ul><li>Đồng hồ 60:00.</li><li>Đọc hiểu văn bản, từ vựng, ngữ pháp tiếng Việt, sửa lỗi.</li><li>Có <strong>đoạn văn dài</strong> trước nhóm 4-7 câu hỏi liên quan.</li></ul><h3 id="phan-3-khoa-hoc" tabindex="-1">Phần 3 - Khoa học <a class="header-anchor" href="#phan-3-khoa-hoc" aria-label="Permalink to “Phần 3 - Khoa học”">​</a></h3><ul><li>Đồng hồ 60:00.</li><li>Theo tổ hợp đã chọn (KHTN hoặc KHXH).</li><li>Mỗi môn ~17 câu (3 môn × 17 ≈ 50).</li></ul><h2 id="trong-khi-lam-bai" tabindex="-1">Trong khi làm bài <a class="header-anchor" href="#trong-khi-lam-bai" aria-label="Permalink to “Trong khi làm bài”">​</a></h2><h3 id="bang-đieu-huong" tabindex="-1">Bảng điều hướng <a class="header-anchor" href="#bang-đieu-huong" aria-label="Permalink to “Bảng điều hướng”">​</a></h3><ul><li>Lưới câu hỏi bên phải (1-50 cho phần hiện tại).</li><li>Màu: xám (chưa làm) / xanh (đã làm) / vàng (đánh dấu).</li></ul><h3 id="chuyen-cau" tabindex="-1">Chuyển câu <a class="header-anchor" href="#chuyen-cau" aria-label="Permalink to “Chuyển câu”">​</a></h3><ul><li>Bấm số câu hoặc dùng <strong>Câu trước / Câu tiếp</strong>.</li></ul><h3 id="đanh-dau-xem-lai" tabindex="-1">Đánh dấu xem lại <a class="header-anchor" href="#đanh-dau-xem-lai" aria-label="Permalink to “Đánh dấu xem lại”">​</a></h3><ul><li>Khi không chắc, bấm icon <strong>🚩 Đánh dấu</strong> → quay lại sau.</li></ul><h3 id="thoat-phan" tabindex="-1">Thoát phần <a class="header-anchor" href="#thoat-phan" aria-label="Permalink to “Thoát phần”">​</a></h3><ul><li>Bấm <strong>Nộp phần này</strong> để chuyển sớm sang phần kế (sẽ không quay lại được).</li><li>Nếu hết giờ, hệ thống tự chuyển.</li></ul><h2 id="khi-het-gio-tong" tabindex="-1">Khi hết giờ tổng <a class="header-anchor" href="#khi-het-gio-tong" aria-label="Permalink to “Khi hết giờ tổng”">​</a></h2><ul><li>Hệ thống tự nộp bài.</li><li>Đưa bạn đến trang <strong>Kết quả</strong>.</li></ul><h2 id="ket-qua" tabindex="-1">Kết quả <a class="header-anchor" href="#ket-qua" aria-label="Permalink to “Kết quả”">​</a></h2><p>Trang kết quả hiển thị:</p><h3 id="tong-điem" tabindex="-1">Tổng điểm <a class="header-anchor" href="#tong-điem" aria-label="Permalink to “Tổng điểm”">​</a></h3><ul><li>Quy về thang điểm chuẩn của HSA (thường 150-1500 điểm, đỉnh 150 câu × ~10 điểm).</li><li>Đối chiếu với điểm chuẩn các trường năm trước (nếu hệ thống tích hợp).</li></ul><h3 id="điem-tung-phan" tabindex="-1">Điểm từng phần <a class="header-anchor" href="#điem-tung-phan" aria-label="Permalink to “Điểm từng phần”">​</a></h3><table tabindex="0"><thead><tr><th>Phần</th><th>Điểm</th><th>/ Tối đa</th></tr></thead><tbody><tr><td>Tư duy định lượng</td><td>...</td><td>500</td></tr><tr><td>Tư duy định tính</td><td>...</td><td>500</td></tr><tr><td>Khoa học</td><td>...</td><td>500</td></tr></tbody></table><h3 id="phan-tich-chi-tiet" tabindex="-1">Phân tích chi tiết <a class="header-anchor" href="#phan-tich-chi-tiet" aria-label="Permalink to “Phân tích chi tiết”">​</a></h3><ul><li><strong>% câu đúng / sai theo chủ đề</strong> (hàm số, lượng giác, hình học, đọc hiểu, ...)</li><li><strong>So sánh với mặt bằng</strong> học viên làm cùng đề.</li><li><strong>Xếp hạng</strong> trong tổng số người làm đề (nếu công khai).</li></ul><h3 id="xem-lai-bai" tabindex="-1">Xem lại bài <a class="header-anchor" href="#xem-lai-bai" aria-label="Permalink to “Xem lại bài”">​</a></h3><ul><li>Bấm <strong>Xem lại</strong> để mở từng câu cùng đáp án + lời giải.</li></ul><p>→ Chi tiết: <a href="./xem-lai-bai-thi">Xem lại bài thi</a>.</p><h2 id="chien-luoc-lam-đe-hsa" tabindex="-1">Chiến lược làm đề HSA <a class="header-anchor" href="#chien-luoc-lam-đe-hsa" aria-label="Permalink to “Chiến lược làm đề HSA”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Thứ tự ưu tiên trong từng phần</p><ol><li>Lướt qua nhanh toàn bộ → khoanh các câu <strong>dễ-trung bình</strong> trước.</li><li>Quay lại các câu <strong>khó / cần tính nhiều</strong>.</li><li>Còn 5 phút → <strong>tô đại</strong> các câu còn lại (không bỏ trống - không trừ điểm câu sai).</li></ol></div><div class="tip custom-block"><p class="custom-block-title">Phân bổ thời gian</p><ul><li><strong>Phần Toán (75 phút / 50 câu)</strong>: ~1.5 phút/câu. Câu dễ &lt; 1 phút, câu khó 2-3 phút.</li><li><strong>Phần Văn (60 phút / 50 câu)</strong>: ~1.2 phút/câu. Đọc đoạn văn xong làm liền cụm 4-7 câu.</li><li><strong>Phần Khoa học (60 phút / 50 câu)</strong>: ~1.2 phút/câu. Câu lý thuyết trước, câu tính sau.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Luyện đề đều đặn</p><ul><li>Trước thi 3 tháng: 1 đề full / tuần.</li><li>Trước thi 1 tháng: 2-3 đề full / tuần.</li><li>Mỗi đề <strong>xong nhớ xem lại đáp án</strong> - đó mới là phần học.</li></ul></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi chọn nhầm tổ hợp Khoa học có đổi lại được không?</strong> → Đề mẫu trên hệ thống có thể cho <strong>làm lại với tổ hợp khác</strong> (nếu đề có nhiều phiên bản). Vào trang xem trước chọn lại trước khi bắt đầu.</p><p><strong>Hết giờ phần 1 nhưng tôi chưa làm hết, có bị trừ điểm câu bỏ trống?</strong> → Không trừ điểm. Câu bỏ trống tính 0 điểm. <strong>Đừng bao giờ bỏ trống</strong> - tô đại còn hơn.</p><p><strong>Điểm tôi đạt trên đề mẫu có sát với điểm thi thật?</strong> → Đề mẫu chất lượng + làm trong điều kiện thi nghiêm túc thường <strong>sai số ±10%</strong> so với thi thật. Quan trọng là dùng để cải thiện, không phải dự đoán.</p><p><strong>Tôi muốn thi cùng bạn để cạnh tranh.</strong> → Cùng bấm vào đề trong khoảng thời gian gần nhau, sau khi nộp <strong>xem bảng xếp hạng</strong> trong cùng đề để so sánh.</p><p><strong>Hệ thống bị lag giữa lúc tôi đang làm phần 3.</strong> → Đăng nhập lại NGAY → vào lịch sử bài thi → tiếp tục bài đang dở (nếu đồng hồ chưa hết).</p>',60)])])}const m=t(l,[["render",r]]);export{d as __pageData,m as default};
